	private long allMask() {
		return factorUniverseMask;
	}

	private static boolean isFiniteNonNegative(double value) {
		return Double.isFinite(value) && value >= 0.0d;
	}

	private static boolean isValidPassRatio(double value) {
		return Double.isFinite(value) && value >= 0.0d && value <= 1.0d;
	}

	private static long bit(int index) {
		return 1L << index;
	}

	private boolean isFilteredFactor(int factorIndex) {
		return factors.get(factorIndex).tupleExpr() instanceof Filter;
	}

	private static boolean hasSelectiveOrderingPassRatio(double passRatio) {
		return Double.isFinite(passRatio) && passRatio >= 0.0d
				&& passRatio <= DEFERRED_FILTER_ORDERING_MAX_PASS_RATIO;
	}

	private double deferredFilterOrderingWeight(JoinOrderPlanner.FilterConstraint filter) {
		if (!canApplyPassRatioToOutputRows(filter) || filter.isLookupCompatible()) {
			return 0.0d;
		}
		double passRatio = filter.getEstimatedPassRatio();
		if (Double.isFinite(passRatio) && passRatio >= 0.0d
				&& passRatio <= DEFERRED_FILTER_ORDERING_MAX_PASS_RATIO) {
			return 1.0d + (DEFERRED_FILTER_ORDERING_MAX_PASS_RATIO - passRatio);
		}
		return 0.0d;
	}

	private int componentCount(String componentMask) {
		if (componentMask == null || "[]".equals(componentMask)) {
			return 0;
		}
		int count = 1;
		for (int i = 0; i < componentMask.length(); i++) {
			if (componentMask.charAt(i) == ',') {
				count++;
			}
		}
		return count;
	}

	private int componentMask(String componentMask) {
		if (componentMask == null || "[]".equals(componentMask)) {
			return 0;
		}
		int mask = 0;
		for (SketchBasedJoinEstimator.Component component : COMPONENT_VALUES) {
			if (componentMask.contains(component.name())) {
				mask |= 1 << component.ordinal();
			}
		}
		return mask;
	}

	private int futureConnectionCount(int factorIndex, long nextMask, long previousMask) {
		return futureJoinConnectionCount(factorIndex, nextMask, previousMask)
				+ futureDeferredFilterConnectionCount(factorIndex, nextMask, previousMask);
	}

	private int futureJoinConnectionCount(int factorIndex, long nextMask, long previousMask) {
		long previousBound = boundVariableMask(previousMask);
		long introducedVars = joinVarMasks[factorIndex] & ~previousBound;
		if (introducedVars == 0L) {
			return 0;
		}

		long nextBound = boundVariableMask(nextMask);
		int futureConnections = 0;
		long remaining = factorUniverseMask & ~nextMask;
		while (remaining != 0L) {
			int i = Long.numberOfTrailingZeros(remaining);
			remaining &= remaining - 1L;
			if ((joinVarMasks[i] & introducedVars) != 0L
					&& (bindingVarMasks[i] & ~nextBound) != 0L) {
				futureConnections++;
			}
		}
		return futureConnections;
	}

	private int futureDeferredFilterConnectionCount(int factorIndex, long nextMask, long previousMask) {
		if (deferredFilters.isEmpty()) {
			return 0;
		}
		long previousBound = boundVariableMask(previousMask);
		long introducedVars = bindingVarMasks[factorIndex] & ~previousBound;
		if (introducedVars == 0L) {
			return 0;
		}

		long nextBound = boundVariableMask(nextMask);
		int futureConnections = 0;
		for (int i = 0; i < deferredFilters.size(); i++) {
			if (deferredFilterOrderingWeight(deferredFilters.get(i)) <= 0.0d) {
				continue;
			}
			long requiredVars = deferredFilterRequiredVarMasks[i];
			if ((previousBound & requiredVars) == requiredVars
					|| (requiredVars & introducedVars) == 0L) {
				continue;
			}
			if ((nextBound & requiredVars) == requiredVars) {
				futureConnections += completedDeferredFilterConnectionWeight(deferredFilters.get(i));
				continue;
			}
			long missingVars = requiredVars & ~nextBound;
			long remaining = factorUniverseMask & ~nextMask;
			while (remaining != 0L) {
				int j = Long.numberOfTrailingZeros(remaining);
				remaining &= remaining - 1L;
				if ((bindingVarMasks[j] & missingVars) != 0L) {
					futureConnections++;
				}
			}
		}
		return futureConnections;
	}

	private int completedDeferredFilterConnectionWeight(JoinOrderPlanner.FilterConstraint filter) {
		return deferredFilterOrderingWeight(filter) > 0.0d ? COMPLETED_DEFERRED_FILTER_CONNECTIONS : 0;
	}

	private static int compareOrder(StatePlan left, StatePlan right) {
		int size = Math.min(left.orderSize(), right.orderSize());
		for (int i = 0; i < size; i++) {
			int comparison = Integer.compare(left.orderAt(i), right.orderAt(i));
			if (comparison != 0) {
				return comparison;
			}
		}
		return Integer.compare(left.orderSize(), right.orderSize());
	}

	private enum JoinStepRole {
		ANCHOR_BRIDGE,
		ANCHOR_LEAF,
		CONTINUE_LATEST_BRIDGE,
		OLDER_BOUND_JOIN,
		OTHER
	}

	private static SketchBasedJoinEstimator.SketchPlannerPath unsupportedPath(TupleExpr tupleExpr) {
		if (tupleExpr instanceof StatementPattern || tupleExpr instanceof BindingSetAssignment) {
			return SketchBasedJoinEstimator.SketchPlannerPath.UNSUPPORTED_SHAPE;
		}
		if (tupleExpr instanceof Filter filter && unwrapFilterPattern(filter) != null) {
			return SketchBasedJoinEstimator.SketchPlannerPath.UNSUPPORTED_SHAPE;
		}
		return SketchBasedJoinEstimator.SketchPlannerPath.UNSUPPORTED_WRAPPER;
	}

	private static StatementPattern unwrapFilterPattern(Filter filter) {
		TupleExpr argument = filter.getArg();
		if (argument instanceof StatementPattern) {
			return (StatementPattern) argument;
		}
		if (argument instanceof Filter) {
			return unwrapFilterPattern((Filter) argument);
		}
		return null;
	}

	static String describeExprOrder(List<TupleExpr> expressions) {
		List<String> described = new ArrayList<>(expressions.size());
		for (TupleExpr expression : expressions) {
			described.add(describeTupleExpr(expression));
		}
		return described.toString();
	}

	static String describeTupleExpr(TupleExpr tupleExpr) {
		if (tupleExpr instanceof StatementPattern statementPattern) {
			return "SP(" + describeVar(statementPattern.getSubjectVar()) + ' '
					+ describeVar(statementPattern.getPredicateVar()) + ' '
					+ describeVar(statementPattern.getObjectVar())
					+ (statementPattern.getContextVar() == null ? ""
							: ' ' + describeVar(statementPattern.getContextVar()))
					+ ')';
		}
		if (tupleExpr instanceof BindingSetAssignment assignment) {
			int rows = 0;
			for (Object ignored : assignment.getBindingSets()) {
				rows++;
			}
			return "BSA(names=" + new TreeSet<>(assignment.getBindingNames()) + ", rows=" + rows + ')';
		}
		if (tupleExpr instanceof Filter filter) {
			return "Filter(" + describeTupleExpr(filter.getArg()) + "; " + filter.getCondition() + ')';
		}
		return tupleExpr.getClass().getSimpleName() + '(' + tupleExpr + ')';
	}

	private static String describeVar(Var var) {
		if (var == null) {
			return "null";
		}
		if (!var.hasValue()) {
			return '?' + Objects.toString(var.getName(), "_");
		}
		Value value = var.getValue();
		return value == null ? '?' + Objects.toString(var.getName(), "_") : value.stringValue();
	}

